import{A as i}from"./chunks/ArticleCardList.kLzyWM7m.js";import{c,o as l,b as t,e as a,d as r,u as s}from"./chunks/vitepress-theme-teek.DkOCGRPR.js";const o=[{id:"ai-native",title:"AI Native 工程思维",icon:"🤖",color:"#a855f7",articles:[{title:"不止于代码：构建 AI 时代全栈工程师的“认知三层塔”",url:"/fullstack/ai-native",description:"在 AI 重塑软件工程的今天，全栈不再是技术的线性叠加，正在从“技术栈堆砌”转向“认知栈重构”。本文提出 “(工程 + 产品) × AI” 的新公式，助力开发者构建“洞察-架构-杠杆”认知三层塔，利用 AI 杠杆让自己进化为价值创造者。"},{title:"重构开发者：AI 时代下的工程师能力图谱与演进指南",url:"/fullstack/ai-engineer-capability",description:""},{title:"读 Anthropic 研究报告，探寻 AI 时代的工程范式重塑",url:"/fullstack/ai-change-work-workflow",description:"本文深度解读了 Anthropic 发布的里程碑报告《AI 如何改变 Anthropic 的工作方式》。我们正处于软件工程史上的又一次“抽象层大迁徙”——当编码成本趋于零，真正的挑战不再是“快”，而是如何对抗“平庸化”与“随机性”。"}]},{id:"ai-coding-guides",title:"AI 编程实践指南",icon:"✨",color:"#c084fc",articles:[{title:"AI 编程工具推荐",url:"/fullstack/ai-coding/resources",description:"本文系统梳理 AI 驱动编程的三大演进范式：Vibe Coding（自然语言零门槛构建）、AI IDE（编辑器深度辅助提效）及 Agentic Engineering（自主工程师执行任务）。并推了对应的主流 AI 编程工具与资源。"},{title:"从 .claude 文件夹读懂 Claude Code",url:"/fullstack/ai-coding/claude-code-deep-dive",description:"针对 AI 编程范式从 Vibe Coding 向 Agentic Engineering 跃迁的背景，深入拆解 Claude Code 工具的核心配置体系。通过分析 .claude 目录结构，系统阐述全局与项目级两级配置的设计思路，详细解读 CLAUDE.md、rules、commands、skills、agents 等模块的功能定位与使用场景，并结合权限隔离、模块化扩展等设计原则，为团队协作提供可落地的配置方案。"}]},{id:"frontend-engineering",title:"前端工程",icon:"🎨",color:"#f59e0b",articles:[{title:"React 设计哲学：AI 协作时代的组件化开发实践指南",url:"/fullstack/react-design-philosophy-ai-augmented",description:"当 AI 承接了 30% 的编码执行时，开发者需通过“规格驱动（SDD）”重夺 70% 的设计主权：从自治组件划分到单向数据流拓扑的深度推演。"},{title:"前端渲染方案选型指南：从 CSR 到 PPR",url:"/fullstack/frontend-rendering-scheme",description:"针对前端渲染方案选型难题，系统解析前端五种渲染方案（CSR/SSR/SSG/ISR/PPR）的核心原理、优缺点及适用场景，提供选型决策树与 VitePress 实践案例。"},{title:"不止于 Fetch：React 服务端状态管理的范式转移与选型深度博弈",url:"/fullstack/server-state-management",description:"本文深度对比 React 生态中 SWR 与 TanStack Query 两大方案。从 stale-while-revalidate 机制到异步状态机架构，涵盖依赖查询、数据转换及架构级乐观更新实战。旨在帮助开发者在复杂业务中构建确定性的服务端状态基座。"},{title:"从原子化到变体驱动：现代 CSS 工程化的架构演进与混合实践指南",url:"/fullstack/css-engineering",description:"本文系统剖析主流 CSS 工程化方案的底层逻辑，提出“样式资产 ROI”评估模型，并针对 Vue/React 生态给出了面向 AI 时代的企业级混合架构选型建议。"},{title:"JAMStack 梳理与实践指南",url:"/fullstack/jamstack",description:"预渲染静态页面 + 动态 API，CDN 分发全球，替代传统动态网站的开发部署范式。 从核心概念、工具链选型（Next.js/Vercel/Supabase/Contentful）到从 0 搭建博客的完整实践，覆盖 JAMStack 适用与不适用场景，帮助判断何时选用该架构。"}]},{id:"fullstack-networking",title:"网络与通信",icon:"🌐",color:"#0ea5e9",articles:[{title:"Web 通信协议全景：从 HTTP 到 WebSocket 的技术选型指南",url:"/fullstack/networking-protocol-selection-guide",description:"文本深入剖析传统 HTTP、流式 HTTP、SSE、WebSocket、Webhooks、HTTP 轮询的原理与特性，结合 AI 场景提供技术选型决策矩阵"},{title:"流式 HTTP 与 SSE 协议：从概念辨析到生产实践",url:"/fullstack/networking-sse-practice",description:"本文辨析流式 HTTP 与 SSE 协议的概念与层次关系，详解客户端与服务端实现方案，提供生产实践完整指南。"},{title:"HTTP 轮询优化指南：退避轮询与长轮询的原理、实战与选型决策",url:"/fullstack/networking-polling-optimization",description:"针对传统固定频率轮询的服务器资源浪费问题，系统分析退避轮询与长轮询两种优化策略的核心原理与运行机制，提供 TypeScript/NestJS 实战代码，并构建技术选型决策树与适用场景速查。"}]},{id:"fullstack-basic",title:"全栈基础素养",icon:"📚",color:"#64748b",articles:[{title:"奥卡姆剃刀原则：从理论到编程设计的实践指南",url:"/fullstack/occams-razor-software-design",description:"在需求边界内追求最小复杂度——不是拒绝复杂，而是不主动制造复杂。本文深入解析奥卡姆剃刀原则在编程与设计中的六大场景：拒绝过度预判、移除冗余逻辑、匹配架构规模、克制依赖引入、封装最小接口、先排查简单原因，并给出三个关键边界。"},{title:"模块化编程实践指南",url:"/fullstack/module-programming-practice-guide",description:"系统梳理 JavaScript 模块化演进（IIFE→CJS→ESM）、TypeScript 类型增强、分层架构与 DDD 实践。从 ES Modules 到大型项目分层架构与工程化实践，构建全栈模块化知识体系。"},{title:"TypeScript 编译与调试完全指南",url:"/fullstack/typescript-compilation-debugging-guide",description:"TypeScript 完善的编译体系与调试工具链，是构建高质量应用的基石。本文深入解析 TypeScript 编译工具链与调试体系，涵盖 tsconfig.json 核心配置、Monorepo 项目配置（extends/references）、source map 调试、ESLint 与 Jest 单元测试等完整实践。"},{title:"聊一聊 TypeScript 中的泛型",url:"/fullstack/typescript-generic-types",description:"泛型将类型作为参数，使代码在多种类型上安全运行，是 TypeScript 类型抽象的核心特性。"}]},{id:"fullstack-resources",title:"工具与资源推荐",icon:"🔧",color:"#0ea5e9",articles:[{title:"全栈技术资源推荐",url:"/fullstack/full-stack-resources",description:"本文系统梳理了现代全栈开发的完整技术图谱与演进范式，为开发者提供了一站式的技术选型指南。文章从基石出发，覆盖 Web 核心语言（JS/TS） 与 主流 UI 框架（React/Vue/Svelte），并推荐以 Tailwind CSS 和 shadcn/ui 为代表的现代样式与组件原语。在核心业务逻辑层，深度对比了轻量化状态管理方案（首推 Zustand/Jotai），并重点解析了数据交互的三大现代架构范式：从基础 Axios 到 React Query 状态调度，再到 tRPC 和 GraphQL 带来的全栈类型安全与多端聚合。在工程化与服务端模块，文章全面拥抱 Vite、Rsbuild 等极速构建工具，并剖析了 Next.js/Nuxt 同构元框架与 NestJS 企业级 Node 服务的最佳适用场景。最后，辅以 Vercel 等现代边缘部署平台及丰富的开源社区学习资源。"}]}],g=JSON.parse('{"title":"全景一览","description":"本系列围绕现代全栈开发的能力体系展开，从 AI 时代的工程思维出发，覆盖前端工程（React/Vue/CSS）、全栈基础素养（TypeScript/JavaScript）、工具与资源推荐等核心领域，帮助构建从\\"认知层 → 技术领域 → 工程能力 → 基础设施\\"的完整全栈知识图谱。","frontmatter":{"date":"2026-03-19T23:05:50.000Z","title":"全景一览","description":"本系列围绕现代全栈开发的能力体系展开，从 AI 时代的工程思维出发，覆盖前端工程（React/Vue/CSS）、全栈基础素养（TypeScript/JavaScript）、工具与资源推荐等核心领域，帮助构建从\\"认知层 → 技术领域 → 工程能力 → 基础设施\\"的完整全栈知识图谱。","categories":["全栈"],"coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/full-stack/insight_stack.png","permalink":"/fullstack/overview"},"headers":[],"relativePath":"fullstack/overview.md","filePath":"01.全栈/00.overview.md"}'),n={name:"fullstack/overview.md"},k=Object.assign(n,{setup(u){return(d,e)=>(l(),c("div",null,[e[0]||(e[0]=t("h1",{id:"全景一览",tabindex:"-1"},[r("全景一览 "),t("a",{class:"header-anchor",href:"#全景一览","aria-label":"Permalink to “全景一览”"},"​")],-1)),a(i,{categories:s(o)},null,8,["categories"])]))}});export{g as __pageData,k as default};
